  ('locality-e9ff7ca9-moex-00265', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '由行政機關所作成之內部函釋，其內容如具備抽象性通案規定要素者，屬於下列何者？', '["法律", "法規命令", "行政計畫", "行政規則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00266', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '甲申請於某山區經營乳牛畜養場，經營業主管機關核准多年後，其畜養場區經水利主管機關依法劃入 水庫集水區，並擬禁止甲繼續經營。營業主管機關應如何處理？', '["職權廢止甲之經營許可，並給予合理補償", "基於公益而撤銷甲之經營許可，毋庸補償", "職權廢止甲之經營許可，且毋庸給予補償", "基於公益而撤銷甲之經營許可，但需補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00267', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '下列何者構成行政處分之負擔？', '["主管機關核發便利商店之營業許可時，附加「不得販賣菸酒給兒童或未滿18歲之青少年」之要求", "林業主管機關核發造林獎勵金時，要求受獎人同意接受主管機關之指導，善加管理林木，不可擅自 拔除", "普通駕駛人年滿75歲，須經體檢合格及通過認知功能測驗後，換發駕照，始得繼續駕駛", "核發外國人觀光簽證時，註記「在國內停留期間不得從事工作或營業」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00268', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '下列何者非屬行政處分？', '["公物之提供公用", "地方政府將某路段劃設禁止停車之紅線", "公告集水區遷村作業實施計畫", "以號誌燈指揮汽機車駕駛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00269', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '關於行政處分附款之敘述，下列何者錯誤？', '["行政機關享有裁量權時，得為附款", "附款之作用係在補充或限制行政處分之效力", "不服附款中之負擔，原則上得單獨對之提起行政救濟", "於個別處分中附加附款，必須要有法律明文規定始得為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00270', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '依據司法實務見解，下列何者非屬行政契約？', '["全民健保特約", "委託行使公權力協議", "國民住宅承租契約", "公費生契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00271', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '主管機關依法調查後仍不能確定納稅義務人之營業額，依據行政程序法與納稅義務人簽訂行政契約， 此等行政契約稱為：', '["行政和解契約", "行政仲裁契約", "行政斡旋契約", "行政調處契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00272', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '有關行政指導，下列敘述何者錯誤？', '["不具法律上之強制力", "應以書面為之", "相對人拒絕指導時行政機關即應停止", "促請特定人為一定作為或不作為之行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00273', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '關於行政罰法所規定罰鍰與行政執行法所規定怠金之區別，下列敘述何者正確？', '["罰鍰係督促履行將來義務之手段，怠金係對過去違法行為予以制裁", "罰鍰針對同一事件得連續處罰，怠金須遵守一行為不二罰原則", "罰鍰屬於行政罰，怠金為行政執行罰", "罰鍰須事先告誡，怠金則無須告誡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('locality-e9ff7ca9-moex-00274', 'locality-e9ff7ca9', 'locality-e9ff7ca9-moex-111-d1a761c9', 'sub-locality-e9ff7ca9-10', NULL, 'single_choice', '甲違反營業場所管制法規，遭人向主管機關檢舉。於機關調查期間，其裁罰依據之法律所定的裁罰上 限從1百萬元罰鍰，修正提高至2百萬元罰鍰。主管機關應依舊法或新法認定裁罰金額之上限，理由 何在？', '["新法，因法律明定以裁處時之法律為準", "舊法，應適用最有利於受處罰者之規定", "新法，應適用不真正溯及既往原則認定", "舊法，因法律明定以行為時為基準時點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:23+00:00", "source_pdf_sha1": "655cf398233b", "answer_pdf_sha1": "2d7adfcfd39e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "403", "s": "0711", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "客家事務行政"}'::jsonb, NULL)
